public class IntegrationService {
    @future(callout=true)
    public static void notifyExternalSystem(Id recordId) {
        System.debug('Async work for ' + recordId);
    }
}

public class EmailJob implements Queueable {
    private Id targetId;
    public EmailJob(Id targetId) {
        this.targetId = targetId;
    }
    public void execute(QueueableContext ctx) {
        System.debug('Sending for ' + targetId);
    }
}

public class AccountBatch implements Database.Batchable<SObject> {
    public Database.QueryLocator start(Database.BatchableContext ctx) {
        return Database.getQueryLocator('SELECT Id FROM Account');
    }
    public void execute(Database.BatchableContext ctx, List<SObject> scope) {
        for (SObject s : scope) { System.debug(s.Id); }
    }
    public void finish(Database.BatchableContext ctx) {
        System.debug('Done');
    }
}
